const UF_NAMES = {"AC": "Acre", "AL": "Alagoas", "AM": "Amazonas", "AP": "Amapá", "BA": "Bahia", "CE": "Ceará", "ES": "Espírito Santo", "GO": "Goiás", "MA": "Maranhão", "MG": "Minas Gerais", "MS": "Mato Grosso do Sul", "MT": "Mato Grosso", "PA": "Pará", "PB": "Paraíba", "PE": "Pernambuco", "PI": "Piauí", "PR": "Paraná", "RJ": "Rio de Janeiro", "RN": "Rio Grande do Norte", "RO": "Rondônia", "RR": "Roraima", "RS": "Rio Grande do Sul", "SC": "Santa Catarina", "SE": "Sergipe", "SP": "São Paulo", "TO": "Tocantins", "DF": "Distrito Federal"};

function normalizeCityName(c) {
  return String(c || "")
    .trim()
    .toUpperCase()
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "");
}

function resolveUF(estadoRaw, cidadeRaw) {
  const uf = String(estadoRaw || "").trim().toUpperCase();
  if (uf && uf.length <= 3 && uf !== "NAN" && uf !== "") return uf;
  const cityKey = normalizeCityName(cidadeRaw);
  if (cityKey && CITY_UF[cityKey]) return CITY_UF[cityKey];
  return "N/D";
}

// ---------- Normalização de transportadora ----------
function normalizePartner(transportadora, macroTp) {
  if (macroTp && String(macroTp).trim()) return String(macroTp).trim();
  const up = String(transportadora || "").toUpperCase();
  if (up.includes("CORREIOS")) return "CORREIOS";
  if (up.includes("DOMINALOG") || up.includes("DLOG")) return "DOMINALOG";
  return String(transportadora || "N/A").trim();
}

// Classifica a transportadora da base "antes da entrega" entre malha própria (BulkyLog/Fulfillment) e terceiros
function classifyOrigemAntes(partner) {
  const up = String(partner || "").toUpperCase();
  if (up.includes("BULKY") || up === "FULFILLMENT") return "BULKYLOG";
  return "TERCEIRA";
}

function findCol(headers, candidates) {
  const norm = (s) => s.toLowerCase().replace(/[^a-z0-9]/g, "");
  const normHeaders = headers.map(norm);
  for (const cand of candidates) {
    const nc = norm(cand);
    const idx = normHeaders.findIndex((h) => h === nc);
    if (idx >= 0) return headers[idx];
  }
  for (const cand of candidates) {
    const nc = norm(cand);
    const idx = normHeaders.findIndex((h) => h.includes(nc));
    if (idx >= 0) return headers[idx];
  }
  return null;
}

function getISOWeek(date) {
  const d = new Date(Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()));
  const dayNum = d.getUTCDay() || 7;
  d.setUTCDate(d.getUTCDate() + 4 - dayNum);
  const yearStart = new Date(Date.UTC(d.getUTCFullYear(), 0, 1));
  return Math.ceil(((d - yearStart) / 86400000 + 1) / 7);
}

// ---------- Parser: base "Devolução Terceiras" (antes da entrega) ----------
function parseCsvToRowsAntes(csvText) {
  const result = Papa.parse(csvText, { header: true, skipEmptyLines: true });
  const headers = result.meta.fields || [];
  const colTransp = findCol(headers, ["transportadora"]);
  const colMacro = findCol(headers, ["macrotp", "macro tp"]);
  const colAno = findCol(headers, ["ano"]);
  const colMes = findCol(headers, ["mes", "mês"]);
  const colSemana = findCol(headers, ["semana"]);
  const colUF = findCol(headers, ["uf", "estado"]);
  const colCidade = findCol(headers, ["cidadedestino", "cidade destino", "cidade"]);

  const rows = [];
  for (const r of result.data) {
    const ano = parseInt(r[colAno], 10);
    const mes = parseInt(r[colMes], 10);
    const semana = parseInt(r[colSemana], 10);
    if (!ano || ano < 2000 || !mes || mes < 1 || mes > 12) continue;
    const partner = normalizePartner(r[colTransp], colMacro ? r[colMacro] : null);
    const uf = resolveUF(colUF ? r[colUF] : null, colCidade ? r[colCidade] : null);
    rows.push([ano, mes, isNaN(semana) ? 0 : semana, partner, uf]);
  }
  return rows;
}

// ---------- Parser: base "Logística Reversa" (pós entrega) ----------
function parseCsvToRowsDepois(csvText) {
  const result = Papa.parse(csvText, { header: true, skipEmptyLines: true });
  const headers = result.meta.fields || [];
  const colValidacao = findCol(headers, ["validacao", "validação"]);
  const colMonth = findCol(headers, ["month", "datacoletaefetivadamonth", "mes"]);
  const colWeek = findCol(headers, ["week", "datacoletaefetivadaweek", "semana"]);
  const colTransp = findCol(headers, ["transportadora"]);
  const colEstado = findCol(headers, ["estado", "uf"]);
  const colCidade = findCol(headers, ["cidade"]);

  const rows = [];
  for (const r of result.data) {
    const monthStr = r[colMonth];
    const weekStr = r[colWeek];
    if (!monthStr) continue;
    const ano = parseInt(String(monthStr).slice(0, 4), 10);
    const mes = parseInt(String(monthStr).slice(5, 7), 10);
    if (!ano || ano < 2000 || !mes || mes < 1 || mes > 12) continue;
    let semana = 0;
    if (weekStr) {
      const d = new Date(weekStr);
      if (!isNaN(d.getTime())) semana = getISOWeek(d);
    }
    const partner = normalizePartner(r[colTransp], null);
    const validRaw = String(r[colValidacao] || "").toUpperCase();
    const validacao = validRaw.includes("NÃO") || validRaw.includes("NAO") ? "NAO_PARCA" : "PARCA";
    const uf = resolveUF(colEstado ? r[colEstado] : null, colCidade ? r[colCidade] : null);
    rows.push([ano, mes, semana, partner, validacao, uf]);
  }
  return rows;
}

// ---------- Agregações (genérico para linhas [ano, mes, semana, partner, uf]) ----------
function aggregate(rows) {
  const anos = Array.from(new Set(rows.map((r) => r[0]))).sort();
  const anoFoco = anos.includes(2026) ? 2026 : anos[anos.length - 1];
  const rowsAno = rows.filter((r) => r[0] === anoFoco);

  const mesesPresentes = Array.from(new Set(rowsAno.map((r) => r[1]))).sort((a, b) => a - b);
  const mesMin = mesesPresentes[0];
  const mesMax = mesesPresentes[mesesPresentes.length - 1];

  const monthlyTotal = {};
  mesesPresentes.forEach((m) => (monthlyTotal[m] = 0));
  rowsAno.forEach((r) => { monthlyTotal[r[1]] = (monthlyTotal[r[1]] || 0) + 1; });

  const weeklyTotal = {};
  rowsAno.forEach((r) => { weeklyTotal[r[2]] = (weeklyTotal[r[2]] || 0) + 1; });

  function groupBy(idx) {
    const byKey = {};
    rowsAno.forEach((r) => {
      const k = r[idx] || "N/D";
      if (!byKey[k]) byKey[k] = {};
      byKey[k][r[1]] = (byKey[k][r[1]] || 0) + 1;
    });
    return Object.entries(byKey)
      .map(([k, mObj]) => ({ key: k, meses: mObj, total: Object.values(mObj).reduce((a, b) => a + b, 0) }))
      .sort((a, b) => b.total - a.total);
  }

  const partnerTotals = groupBy(3).map((x) => ({ partner: x.key, meses: x.meses, total: x.total }));
  const ufTotals = groupBy(4).map((x) => ({ uf: x.key, meses: x.meses, total: x.total }));

  const totalGeral = rowsAno.length;

  return { anoFoco, mesMin, mesMax, mesesPresentes, monthlyTotal, weeklyTotal, partnerTotals, ufTotals, totalGeral };
}

// Agregação genérica por categoria (2 grupos), com detalhamento mensal e semanal
function aggregateByCategory(rows, categoryFn) {
  const anos = Array.from(new Set(rows.map((r) => r[0]))).sort();
  const anoFoco = anos.includes(2026) ? 2026 : anos[anos.length - 1];
  const rowsAno = rows.filter((r) => r[0] === anoFoco);

  const mesesPresentes = Array.from(new Set(rowsAno.map((r) => r[1]))).sort((a, b) => a - b);

  const monthlyByCat = {};
  const weeklyByCat = {};
  rowsAno.forEach((r) => {
    const c = categoryFn(r);
    if (!monthlyByCat[c]) monthlyByCat[c] = {};
    if (!weeklyByCat[c]) weeklyByCat[c] = {};
    monthlyByCat[c][r[1]] = (monthlyByCat[c][r[1]] || 0) + 1;
    weeklyByCat[c][r[2]] = (weeklyByCat[c][r[2]] || 0) + 1;
  });

  const totalByCat = {};
  Object.keys(monthlyByCat).forEach((c) => {
    totalByCat[c] = Object.values(monthlyByCat[c]).reduce((a, b) => a + b, 0);
  });

  return { anoFoco, mesesPresentes, monthlyByCat, weeklyByCat, totalByCat };
}

function pctVar(atual, anterior) {
  if (!anterior) return null;
  return ((atual - anterior) / anterior) * 100;
}

function VarBadge({ value }) {
  if (value === null || value === undefined || !isFinite(value)) {
    return <span style={{ color: C.cinzaTexto, fontSize: 13 }}>—</span>;
  }
  const up = value >= 0;
  const color = up ? C.verde : C.vermelho;
  const bg = up ? C.verdeLight : C.vermelhoLight;
  return (
    <span style={{ color, background: bg, borderRadius: 6, padding: "2px 8px", fontSize: 13, fontWeight: 600, display: "inline-flex", alignItems: "center", gap: 4 }}>
      {up ? "▲" : "▼"} {Math.abs(value).toFixed(1)}%
    </span>
  );
}

function KpiCard({ label, value, sub, accent }) {
  return (
    <div style={{ background: C.cinzaCard, border: `1px solid ${C.cinzaBorda}`, borderRadius: 12, padding: "16px 18px", flex: 1, minWidth: 180, borderTop: `3px solid ${accent || C.laranja}` }}>
      <div style={{ fontSize: 12.5, color: C.cinzaTexto, fontWeight: 600, textTransform: "uppercase", letterSpacing: 0.3 }}>{label}</div>
      <div style={{ fontSize: 28, fontWeight: 700, color: C.texto, marginTop: 4 }}>{value}</div>
      {sub && <div style={{ marginTop: 6 }}>{sub}</div>}
    </div>
  );
}

// Ranking genérico (usado para Por Transportadora e Por Estado)
function RankingList({ items, labelKey, totalGeral, prevMonth, lastMonth, labelMap, highlight, onHover }) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
      {items.map((p, i) => {
        const varUltimo = prevMonth ? pctVar(p.meses[lastMonth] || 0, p.meses[prevMonth] || 0) : null;
        const pct = (p.total / totalGeral) * 100;
        const key = p[labelKey];
        const isHi = highlight && highlight === key;
        return (
          <div key={key}
            onMouseEnter={() => onHover && onHover(key)}
            onMouseLeave={() => onHover && onHover(null)}
            style={{
              display: "flex", alignItems: "center", gap: 12, padding: "10px 12px", borderRadius: 8,
              background: isHi ? C.azulLight : (i % 2 === 0 ? C.cinzaFundo : "transparent"),
              cursor: onHover ? "pointer" : "default", transition: "background 0.15s",
            }}>
            <div style={{ width: 22, fontSize: 12.5, color: C.cinzaTexto, fontWeight: 700 }}>{i + 1}</div>
            <div style={{ width: 190, fontSize: 13.5, fontWeight: 600 }}>{labelMap ? (labelMap[key] || key) : key}</div>
            <div style={{ flex: 1, background: C.cinzaBorda, borderRadius: 6, height: 10, overflow: "hidden" }}>
              <div style={{ width: `${Math.max(pct, 1.5)}%`, height: "100%", background: SERIES_COLORS[i % SERIES_COLORS.length], borderRadius: 6 }} />
            </div>
            <div style={{ width: 70, textAlign: "right", fontSize: 13.5, fontWeight: 700 }}>{p.total.toLocaleString("pt-BR")}</div>
            <div style={{ width: 55, textAlign: "right", fontSize: 12, color: C.cinzaTexto }}>{pct.toFixed(1)}%</div>
            <div style={{ width: 90, textAlign: "right" }}><VarBadge value={varUltimo} /></div>
          </div>
        );
      })}
    </div>
  );
}

// ============ Mapa interativo do Brasil (coroplético) ============
function BrazilMap({ ufTotals, corBase, totalGeral }) {
  const [hoverUF, setHoverUF] = useState(null);
  const valueByUF = useMemo(() => {
    const m = {};
    ufTotals.forEach((u) => { m[u.uf] = u.total; });
    return m;
  }, [ufTotals]);

  const maxVal = Math.max(1, ...Object.values(valueByUF).filter((v, i, arr) => true));
  const maxValReal = Math.max(1, ...ufTotals.filter((u) => u.uf !== "N/D").map((u) => u.total));

  function colorFor(uf) {
    const v = valueByUF[uf] || 0;
    if (v === 0) return "#EDEBE6";
    const t = Math.sqrt(v / maxValReal); // raiz p/ suavizar distribuição bem concentrada
    // interpola entre cinza claro e a cor principal
    const from = { r: 253, g: 246, b: 236 };
    const hex = corBase.replace("#", "");
    const to = { r: parseInt(hex.slice(0, 2), 16), g: parseInt(hex.slice(2, 4), 16), b: parseInt(hex.slice(4, 6), 16) };
    const r = Math.round(from.r + (to.r - from.r) * t);
    const g = Math.round(from.g + (to.g - from.g) * t);
    const b = Math.round(from.b + (to.b - from.b) * t);
    return `rgb(${r},${g},${b})`;
  }

  const hoverData = hoverUF ? ufTotals.find((u) => u.uf === hoverUF) : null;

  return (
    <div style={{ position: "relative", display: "flex", gap: 20, alignItems: "flex-start", flexWrap: "wrap" }}>
      <div style={{ position: "relative", flex: "0 0 auto" }}>
        <svg viewBox={BR_MAP_VIEWBOX} style={{ width: 340, height: 340 }}>
          {Object.entries(BR_MAP_PATHS).map(([uf, d]) => (
            <path
              key={uf}
              d={d}
              fill={colorFor(uf)}
              stroke={hoverUF === uf ? C.texto : "#fff"}
              strokeWidth={hoverUF === uf ? 1.6 : 0.7}
              onMouseEnter={() => setHoverUF(uf)}
              onMouseLeave={() => setHoverUF(null)}
              style={{ cursor: "pointer", transition: "fill 0.15s" }}
            />
          ))}
        </svg>
        {hoverData && (
          <div style={{
            position: "absolute", top: 8, left: 8, background: C.texto, color: "#fff",
            borderRadius: 8, padding: "8px 12px", fontSize: 12.5, pointerEvents: "none",
            boxShadow: "0 4px 12px rgba(0,0,0,0.18)", minWidth: 140,
          }}>
            <div style={{ fontWeight: 700 }}>{UF_NAMES[hoverUF] || hoverUF} ({hoverUF})</div>
            <div>{hoverData.total.toLocaleString("pt-BR")} notas</div>
            <div style={{ color: "#D1D5DB" }}>{((hoverData.total / totalGeral) * 100).toFixed(1)}% do total</div>
          </div>
        )}
      </div>
      <div style={{ flex: 1, minWidth: 260 }}>
        <div style={{ fontSize: 12.5, color: C.cinzaTexto, marginBottom: 8 }}>
          Passe o mouse sobre um estado no mapa ou na lista para destacar
        </div>
        <div style={{ maxHeight: 320, overflowY: "auto", paddingRight: 4 }}>
          <RankingList
            items={ufTotals.filter((u) => u.uf !== "N/D")}
            labelKey="uf"
            totalGeral={totalGeral}
            prevMonth={null}
            lastMonth={null}
            labelMap={UF_NAMES}
            highlight={hoverUF}
            onHover={setHoverUF}
          />
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 8, marginTop: 12, fontSize: 11.5, color: C.cinzaTexto }}>
          <span>Menos</span>
          <div style={{ display: "flex", height: 8, width: 100, borderRadius: 4, overflow: "hidden" }}>
            {[0.1, 0.3, 0.5, 0.7, 0.9, 1].map((t, i) => {
              const from = { r: 253, g: 246, b: 236 };
              const hex = corBase.replace("#", "");
              const to = { r: parseInt(hex.slice(0, 2), 16), g: parseInt(hex.slice(2, 4), 16), b: parseInt(hex.slice(4, 6), 16) };
              const r = Math.round(from.r + (to.r - from.r) * t);
              const g = Math.round(from.g + (to.g - from.g) * t);
              const b = Math.round(from.b + (to.b - from.b) * t);
              return <div key={i} style={{ flex: 1, background: `rgb(${r},${g},${b})` }} />;
            })}
          </div>
          <span>Mais</span>
        </div>
      </div>
    </div>
  );
}

// ============ Comparação por categoria (2 grupos) — reutilizável ============
function CategoryComparisonView({ agg, catA, catB, labelA, labelB, colorA, colorB }) {
  const { mesesPresentes, monthlyByCat, weeklyByCat, totalByCat, anoFoco } = agg;
  const totalA = totalByCat[catA] || 0;
  const totalB = totalByCat[catB] || 0;
  const totalGeral = totalA + totalB;

  const mesMin = mesesPresentes[0];
  const mesMax = mesesPresentes[mesesPresentes.length - 1];
  const prevMonth = mesesPresentes[mesesPresentes.length - 2];
  const periodoLabel = mesMin && mesMax
    ? (mesMin === mesMax ? `${MESES[mesMin - 1]}/${anoFoco}` : `${MESES[mesMin - 1]}–${MESES[mesMax - 1]}/${anoFoco}`)
    : "—";

  const mA = monthlyByCat[catA] || {};
  const mB = monthlyByCat[catB] || {};
  const monthlyData = mesesPresentes.map((m) => ({ mes: MESES[m - 1], [labelA]: mA[m] || 0, [labelB]: mB[m] || 0 }));

  const wA = weeklyByCat[catA] || {};
  const wB = weeklyByCat[catB] || {};
  const semanas = Array.from(new Set([...Object.keys(wA), ...Object.keys(wB)].map((s) => parseInt(s, 10)))).sort((a, b) => a - b);
  const weeklyData = semanas.map((s) => ({ semana: "S" + s, [labelA]: wA[s] || 0, [labelB]: wB[s] || 0 }));

  const varA = mesMax ? pctVar(mA[mesMax] || 0, prevMonth ? (mA[prevMonth] || 0) : null) : null;
  const varB = mesMax ? pctVar(mB[mesMax] || 0, prevMonth ? (mB[prevMonth] || 0) : null) : null;

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 18 }}>
      <div style={{ display: "flex", gap: 14, flexWrap: "wrap" }}>
        <KpiCard label={`Total ${labelA}`} value={totalA.toLocaleString("pt-BR")} accent={colorA}
          sub={<span style={{ fontSize: 12.5, color: C.cinzaTexto }}>{totalGeral > 0 ? ((totalA / totalGeral) * 100).toFixed(0) + "% do total" : ""}</span>} />
        <KpiCard label={`Total ${labelB}`} value={totalB.toLocaleString("pt-BR")} accent={colorB}
          sub={<span style={{ fontSize: 12.5, color: C.cinzaTexto }}>{totalGeral > 0 ? ((totalB / totalGeral) * 100).toFixed(0) + "% do total" : ""}</span>} />
        <KpiCard label={`Variação ${MESES[(mesMax || 1) - 1]} — ${labelA}`} value={mesMax ? (mA[mesMax] || 0).toLocaleString("pt-BR") : "—"} accent={colorA} sub={<VarBadge value={varA} />} />
        <KpiCard label={`Variação ${MESES[(mesMax || 1) - 1]} — ${labelB}`} value={mesMax ? (mB[mesMax] || 0).toLocaleString("pt-BR") : "—"} accent={colorB} sub={<VarBadge value={varB} />} />
      </div>

      <div style={{ background: C.cinzaCard, border: `1px solid ${C.cinzaBorda}`, borderRadius: 12, padding: 18 }}>
        <div style={{ fontWeight: 700, fontSize: 14.5, marginBottom: 12 }}>Comparação Mensal — {periodoLabel}</div>
        <ResponsiveContainer width="100%" height={270}>
          <BarChart data={monthlyData}>
            <CartesianGrid strokeDasharray="3 3" stroke={C.cinzaBorda} vertical={false} />
            <XAxis dataKey="mes" tick={{ fontSize: 12.5, fill: C.cinzaTexto }} axisLine={{ stroke: C.cinzaBorda }} tickLine={false} />
            <YAxis tick={{ fontSize: 12.5, fill: C.cinzaTexto }} axisLine={false} tickLine={false} />
            <Tooltip contentStyle={{ borderRadius: 8, border: `1px solid ${C.cinzaBorda}`, fontSize: 13 }} />
            <Legend wrapperStyle={{ fontSize: 12 }} />
            <Bar dataKey={labelA} fill={colorA} radius={[4, 4, 0, 0]} />
            <Bar dataKey={labelB} fill={colorB} radius={[4, 4, 0, 0]} />
          </BarChart>
        </ResponsiveContainer>
      </div>

      <div style={{ background: C.cinzaCard, border: `1px solid ${C.cinzaBorda}`, borderRadius: 12, padding: 18 }}>
        <div style={{ fontWeight: 700, fontSize: 14.5, marginBottom: 12 }}>Comparação Semanal — {periodoLabel}</div>
        <ResponsiveContainer width="100%" height={230}>
          <LineChart data={weeklyData}>
            <CartesianGrid strokeDasharray="3 3" stroke={C.cinzaBorda} vertical={false} />
            <XAxis dataKey="semana" tick={{ fontSize: 10.5, fill: C.cinzaTexto }} axisLine={{ stroke: C.cinzaBorda }} tickLine={false} interval={1} />
            <YAxis tick={{ fontSize: 12.5, fill: C.cinzaTexto }} axisLine={false} tickLine={false} />
            <Tooltip contentStyle={{ borderRadius: 8, border: `1px solid ${C.cinzaBorda}`, fontSize: 13 }} />
            <Legend wrapperStyle={{ fontSize: 12 }} />
            <Line type="monotone" dataKey={labelA} stroke={colorA} strokeWidth={2.2} dot={{ r: 2 }} />
            <Line type="monotone" dataKey={labelB} stroke={colorB} strokeWidth={2.2} dot={{ r: 2 }} />
          </LineChart>
        </ResponsiveContainer>
      </div>

      <div style={{ background: C.cinzaCard, border: `1px solid ${C.cinzaBorda}`, borderRadius: 12, padding: 18, overflowX: "auto" }}>
        <div style={{ fontWeight: 700, fontSize: 14.5, marginBottom: 12 }}>Tabela Mensal — {labelA} x {labelB}</div>
        <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 13 }}>
          <thead>
            <tr style={{ borderBottom: `2px solid ${C.cinzaBorda}` }}>
              <th style={{ textAlign: "left", padding: "8px 6px" }}>Mês</th>
              <th style={{ textAlign: "right", padding: "8px 6px" }}>{labelA}</th>
              <th style={{ textAlign: "right", padding: "8px 6px" }}>{labelB}</th>
              <th style={{ textAlign: "right", padding: "8px 6px" }}>% {labelA}</th>
              <th style={{ textAlign: "right", padding: "8px 6px" }}>% {labelB}</th>
            </tr>
          </thead>
          <tbody>
            {monthlyData.map((r, i) => {
              const tot = (r[labelA] || 0) + (r[labelB] || 0);
              return (
                <tr key={r.mes} style={{ borderBottom: `1px solid ${C.cinzaBorda}`, background: i % 2 === 0 ? C.cinzaFundo : "transparent" }}>
                  <td style={{ padding: "7px 6px", fontWeight: 600 }}>{r.mes}</td>
                  <td style={{ textAlign: "right", padding: "7px 6px" }}>{r[labelA].toLocaleString("pt-BR")}</td>
                  <td style={{ textAlign: "right", padding: "7px 6px" }}>{r[labelB].toLocaleString("pt-BR")}</td>
                  <td style={{ textAlign: "right", padding: "7px 6px", color: C.cinzaTexto }}>{tot > 0 ? ((r[labelA] / tot) * 100).toFixed(0) + "%" : "—"}</td>
                  <td style={{ textAlign: "right", padding: "7px 6px", color: C.cinzaTexto }}>{tot > 0 ? ((r[labelB] / tot) * 100).toFixed(0) + "%" : "—"}</td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// ============ Bloco reutilizável: Visão Geral / Ranking / Estado / Tabela para um dataset ============
function DatasetView({ agg, subtab, setSubtab, corPrincipal, tituloVolume, categoryView }) {
  const { mesesPresentes, monthlyTotal, weeklyTotal, partnerTotals, ufTotals, totalGeral, anoFoco, mesMin, mesMax } = agg;
  const lastMonth = mesMax;
  const prevMonth = mesesPresentes[mesesPresentes.length - 2];
  const lastVol = monthlyTotal[lastMonth] || 0;
  const varMoM = prevMonth ? pctVar(lastVol, monthlyTotal[prevMonth] || 0) : null;
  const mediaMovel = mesesPresentes.length > 0 ? Math.round(totalGeral / mesesPresentes.length) : 0;
  const liderAtual = partnerTotals[0];

  const periodoLabel = mesMin && mesMax
    ? (mesMin === mesMax ? `${MESES[mesMin - 1]}/${anoFoco}` : `${MESES[mesMin - 1]}–${MESES[mesMax - 1]}/${anoFoco}`)
    : "—";

  const monthlyChartData = mesesPresentes.map((m) => ({ mes: MESES[m - 1], volume: monthlyTotal[m] || 0 }));
  const weeklyChartData = Object.keys(weeklyTotal).map((s) => parseInt(s, 10)).sort((a, b) => a - b).map((s) => ({ semana: "S" + s, volume: weeklyTotal[s] }));

  const top8 = partnerTotals.slice(0, 8);
  const outros = partnerTotals.slice(8);
  const stackedData = mesesPresentes.map((m) => {
    const entry = { mes: MESES[m - 1] };
    top8.forEach((p) => { entry[p.partner] = p.meses[m] || 0; });
    if (outros.length > 0) entry["Outros"] = outros.reduce((acc, p) => acc + (p.meses[m] || 0), 0);
    return entry;
  });
  const stackKeys = [...top8.map((p) => p.partner), ...(outros.length > 0 ? ["Outros"] : [])];

  const naoIdentificado = ufTotals.find((u) => u.uf === "N/D");

  return (
    <div>
      <div style={{ display: "flex", gap: 14, flexWrap: "wrap", marginBottom: 20 }}>
        <KpiCard label={`Volume Total — ${tituloVolume}`} value={totalGeral.toLocaleString("pt-BR")} accent={corPrincipal}
          sub={<span style={{ fontSize: 12.5, color: C.cinzaTexto }}>{mesesPresentes.length} meses · {periodoLabel}</span>} />
        <KpiCard label={`Volume — ${MESES[lastMonth - 1]}/${anoFoco}`} value={lastVol.toLocaleString("pt-BR")} accent={C.azul}
          sub={<VarBadge value={varMoM} />} />
        <KpiCard label="Média Mensal" value={mediaMovel.toLocaleString("pt-BR")} accent={C.amarelo}
          sub={<span style={{ fontSize: 12.5, color: C.cinzaTexto }}>notas / mês</span>} />
        <KpiCard label="Transportadora Líder" value={liderAtual ? liderAtual.partner : "—"} accent={C.verde}
          sub={<span style={{ fontSize: 12.5, color: C.cinzaTexto }}>{liderAtual ? `${liderAtual.total.toLocaleString("pt-BR")} (${((liderAtual.total / totalGeral) * 100).toFixed(0)}%)` : ""}</span>} />
      </div>

      <div style={{ display: "flex", gap: 4, marginBottom: 16, borderBottom: `1px solid ${C.cinzaBorda}`, flexWrap: "wrap" }}>
        {[
          ["visao", "Visão Geral"],
          ["parceiros", "Por Transportadora"],
          ["mapa", "🗺️ Mapa por Estado"],
          ...(categoryView ? [["categoria", categoryView.tabLabel]] : []),
          ["tabela", "Tabela Completa"],
        ].map(([key, label]) => (
          <button key={key} onClick={() => setSubtab(key)} style={{
            padding: "10px 16px", border: "none", background: "transparent", cursor: "pointer", fontSize: 13.5, fontWeight: 600,
            color: subtab === key ? corPrincipal : C.cinzaTexto,
            borderBottom: subtab === key ? `2px solid ${corPrincipal}` : "2px solid transparent", marginBottom: -1,
          }}>{label}</button>
        ))}
      </div>

      {subtab === "visao" && (
        <div style={{ display: "flex", flexDirection: "column", gap: 18 }}>
          <div style={{ background: C.cinzaCard, border: `1px solid ${C.cinzaBorda}`, borderRadius: 12, padding: 18 }}>
            <div style={{ fontWeight: 700, fontSize: 14.5, marginBottom: 12 }}>Volume Mensal — {periodoLabel}</div>
            <ResponsiveContainer width="100%" height={250}>
              <AreaChart data={monthlyChartData}>
                <defs>
                  <linearGradient id={`grad-${corPrincipal}`} x1="0" y1="0" x2="0" y2="1">
                    <stop offset="0%" stopColor={corPrincipal} stopOpacity={0.35} />
                    <stop offset="100%" stopColor={corPrincipal} stopOpacity={0.02} />
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" stroke={C.cinzaBorda} vertical={false} />
                <XAxis dataKey="mes" tick={{ fontSize: 12.5, fill: C.cinzaTexto }} axisLine={{ stroke: C.cinzaBorda }} tickLine={false} />
                <YAxis tick={{ fontSize: 12.5, fill: C.cinzaTexto }} axisLine={false} tickLine={false} />
                <Tooltip contentStyle={{ borderRadius: 8, border: `1px solid ${C.cinzaBorda}`, fontSize: 13 }} />
                <Area type="monotone" dataKey="volume" stroke={corPrincipal} strokeWidth={2.5} fill={`url(#grad-${corPrincipal})`} name="Notas" />
              </AreaChart>
            </ResponsiveContainer>
          </div>

          <div style={{ background: C.cinzaCard, border: `1px solid ${C.cinzaBorda}`, borderRadius: 12, padding: 18 }}>
            <div style={{ fontWeight: 700, fontSize: 14.5, marginBottom: 12 }}>Volume Semanal — {periodoLabel}</div>
            <ResponsiveContainer width="100%" height={210}>
              <LineChart data={weeklyChartData}>
                <CartesianGrid strokeDasharray="3 3" stroke={C.cinzaBorda} vertical={false} />
                <XAxis dataKey="semana" tick={{ fontSize: 11, fill: C.cinzaTexto }} axisLine={{ stroke: C.cinzaBorda }} tickLine={false} interval={1} />
                <YAxis tick={{ fontSize: 12.5, fill: C.cinzaTexto }} axisLine={false} tickLine={false} />
                <Tooltip contentStyle={{ borderRadius: 8, border: `1px solid ${C.cinzaBorda}`, fontSize: 13 }} />
                <Line type="monotone" dataKey="volume" stroke={C.azul} strokeWidth={2.2} dot={{ r: 2.5 }} name="Notas" />
              </LineChart>
            </ResponsiveContainer>
          </div>

          <div style={{ background: C.cinzaCard, border: `1px solid ${C.cinzaBorda}`, borderRadius: 12, padding: 18 }}>
            <div style={{ fontWeight: 700, fontSize: 14.5, marginBottom: 12 }}>Composição Mensal por Transportadora (Top 8 + Outros)</div>
            <ResponsiveContainer width="100%" height={270}>
              <BarChart data={stackedData}>
                <CartesianGrid strokeDasharray="3 3" stroke={C.cinzaBorda} vertical={false} />
                <XAxis dataKey="mes" tick={{ fontSize: 12.5, fill: C.cinzaTexto }} axisLine={{ stroke: C.cinzaBorda }} tickLine={false} />
                <YAxis tick={{ fontSize: 12.5, fill: C.cinzaTexto }} axisLine={false} tickLine={false} />
                <Tooltip contentStyle={{ borderRadius: 8, border: `1px solid ${C.cinzaBorda}`, fontSize: 13 }} />
                <Legend wrapperStyle={{ fontSize: 11.5 }} />
                {stackKeys.map((k, i) => (
                  <Bar key={k} dataKey={k} stackId="a" fill={k === "Outros" ? C.cinzaTexto : SERIES_COLORS[i % SERIES_COLORS.length]} />
                ))}
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      )}

      {subtab === "parceiros" && (
        <div style={{ background: C.cinzaCard, border: `1px solid ${C.cinzaBorda}`, borderRadius: 12, padding: 18 }}>
          <div style={{ fontWeight: 700, fontSize: 14.5, marginBottom: 4 }}>Ranking por Transportadora — {periodoLabel}</div>
          <div style={{ fontSize: 12.5, color: C.cinzaTexto, marginBottom: 14 }}>Correios e Dominalog já consolidados</div>
          <RankingList items={partnerTotals} labelKey="partner" totalGeral={totalGeral} prevMonth={prevMonth} lastMonth={lastMonth} />
        </div>
      )}

      {subtab === "mapa" && (
        <div style={{ background: C.cinzaCard, border: `1px solid ${C.cinzaBorda}`, borderRadius: 12, padding: 18 }}>
          <div style={{ fontWeight: 700, fontSize: 14.5, marginBottom: 4 }}>Mapa de Volume por Estado — {periodoLabel}</div>
          <div style={{ fontSize: 12.5, color: C.cinzaTexto, marginBottom: 16 }}>
            Estado obtido diretamente da base; quando ausente, identificado automaticamente pela cidade
            {naoIdentificado ? <> · <strong style={{ color: C.vermelho }}>{naoIdentificado.total.toLocaleString("pt-BR")} notas sem estado identificado</strong></> : null}
          </div>
          <BrazilMap ufTotals={ufTotals} corBase={corPrincipal} totalGeral={totalGeral} />
        </div>
      )}

      {subtab === "categoria" && categoryView && categoryView.node}

      {subtab === "tabela" && (
        <div style={{ background: C.cinzaCard, border: `1px solid ${C.cinzaBorda}`, borderRadius: 12, padding: 18, overflowX: "auto" }}>
          <div style={{ fontWeight: 700, fontSize: 14.5, marginBottom: 12 }}>Tabela Completa — {periodoLabel}</div>
          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 13 }}>
            <thead>
              <tr style={{ borderBottom: `2px solid ${C.cinzaBorda}` }}>
                <th style={{ textAlign: "left", padding: "8px 6px" }}>Transportadora</th>
                {mesesPresentes.map((m) => (<th key={m} style={{ textAlign: "right", padding: "8px 6px" }}>{MESES[m - 1]}</th>))}
                <th style={{ textAlign: "right", padding: "8px 6px", fontWeight: 800 }}>Total</th>
              </tr>
            </thead>
            <tbody>
              {partnerTotals.map((p, i) => (
                <tr key={p.partner} style={{ borderBottom: `1px solid ${C.cinzaBorda}`, background: i % 2 === 0 ? C.cinzaFundo : "transparent" }}>
                  <td style={{ padding: "7px 6px", fontWeight: 600 }}>{p.partner}</td>
                  {mesesPresentes.map((m) => (
                    <td key={m} style={{ textAlign: "right", padding: "7px 6px", color: (p.meses[m] || 0) === 0 ? C.cinzaTexto : C.texto }}>{(p.meses[m] || 0).toLocaleString("pt-BR")}</td>
                  ))}
                  <td style={{ textAlign: "right", padding: "7px 6px", fontWeight: 800 }}>{p.total.toLocaleString("pt-BR")}</td>
                </tr>
              ))}
            </tbody>
            <tfoot>
              <tr style={{ borderTop: `2px solid ${C.cinzaBorda}` }}>
                <td style={{ padding: "8px 6px", fontWeight: 800 }}>TOTAL</td>
                {mesesPresentes.map((m) => (<td key={m} style={{ textAlign: "right", padding: "8px 6px", fontWeight: 800 }}>{(monthlyTotal[m] || 0).toLocaleString("pt-BR")}</td>))}
                <td style={{ textAlign: "right", padding: "8px 6px", fontWeight: 800 }}>{totalGeral.toLocaleString("pt-BR")}</td>
              </tr>
            </tfoot>
          </table>
        </div>
      )}
    </div>
  );
}

// ================= APP =================
export default function App() {
  const [rowsAntes, setRowsAntes] = useState(DEFAULT_ROWS_ANTES);
  const [rowsDepois, setRowsDepois] = useState(DEFAULT_ROWS_DEPOIS);
  const [fileNameAntes, setFileNameAntes] = useState("Base padrão — Devolução Terceiras (Jan–Mai/2026)");
  const [fileNameDepois, setFileNameDepois] = useState("Base padrão — Logística Reversa (Jan–Mai/2026)");
  const [somenteParca, setSomenteParca] = useState(true);
  const [section, setSection] = useState("antes"); // antes | depois | comparacao
  const [subtabAntes, setSubtabAntes] = useState("visao");
  const [subtabDepois, setSubtabDepois] = useState("visao");
  const [loadError, setLoadError] = useState(null);

  const rowsDepoisFiltradas = useMemo(() => {
    const base = somenteParca ? rowsDepois.filter((r) => r[4] === "PARCA") : rowsDepois;
    return base.map((r) => [r[0], r[1], r[2], r[3], r[5]]);
  }, [rowsDepois, somenteParca]);

  const aggAntes = useMemo(() => aggregate(rowsAntes), [rowsAntes]);
  const aggDepois = useMemo(() => aggregate(rowsDepoisFiltradas), [rowsDepoisFiltradas]);

  // Antes da entrega: Transportadora Terceira x BulkyLog (malha própria)
  const aggAntesCategoria = useMemo(
    () => aggregateByCategory(rowsAntes, (r) => classifyOrigemAntes(r[3])),
    [rowsAntes]
  );
  // Pós entrega: Parça x Não Parça (usa a base completa, independente do toggle "Somente Parça")
  const aggDepoisCategoria = useMemo(
    () => aggregateByCategory(rowsDepois, (r) => (r[4] === "PARCA" ? "PARCA" : "NAO_PARCA")),
    [rowsDepois]
  );

  const handleFileAntes = useCallback((file) => {
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const parsed = parseCsvToRowsAntes(e.target.result);
        if (parsed.length === 0) { setLoadError("Não encontrei linhas válidas no CSV de Devolução Terceiras (antes da entrega)."); return; }
        setRowsAntes(parsed); setFileNameAntes(file.name); setLoadError(null);
      } catch (err) { setLoadError("Erro ao ler o arquivo: " + err.message); }
    };
    reader.readAsText(file, "UTF-8");
  }, []);

  const handleFileDepois = useCallback((file) => {
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const parsed = parseCsvToRowsDepois(e.target.result);
        if (parsed.length === 0) { setLoadError("Não encontrei linhas válidas no CSV de Logística Reversa (pós entrega)."); return; }
        setRowsDepois(parsed); setFileNameDepois(file.name); setLoadError(null);
      } catch (err) { setLoadError("Erro ao ler o arquivo: " + err.message); }
    };
    reader.readAsText(file, "UTF-8");
  }, []);

  // ---------- Comparação ----------
  const mesesComp = useMemo(() => {
    const set = new Set([...aggAntes.mesesPresentes, ...aggDepois.mesesPresentes]);
    return Array.from(set).sort((a, b) => a - b);
  }, [aggAntes, aggDepois]);

  const comparacaoMensal = mesesComp.map((m) => ({
    mes: MESES[m - 1],
    Antes: aggAntes.monthlyTotal[m] || 0,
    Depois: aggDepois.monthlyTotal[m] || 0,
  }));

  const semanasComp = useMemo(() => {
    const set = new Set([
      ...Object.keys(aggAntes.weeklyTotal).map((s) => parseInt(s, 10)),
      ...Object.keys(aggDepois.weeklyTotal).map((s) => parseInt(s, 10)),
    ]);
    return Array.from(set).sort((a, b) => a - b);
  }, [aggAntes, aggDepois]);

  const comparacaoSemanal = semanasComp.map((s) => ({
    semana: "S" + s,
    Antes: aggAntes.weeklyTotal[s] || 0,
    Depois: aggDepois.weeklyTotal[s] || 0,
  }));

  const totalAntes = aggAntes.totalGeral;
  const totalDepois = aggDepois.totalGeral;
  const proporcao = totalAntes > 0 ? (totalDepois / totalAntes) : null;

  const exportExcel = () => {
    const wb = XLSX.utils.book_new();

    const buildSheet = (agg) => {
      const header = ["Transportadora", ...agg.mesesPresentes.map((m) => MESES[m - 1]), "Total"];
      const data = agg.partnerTotals.map((p) => [p.partner, ...agg.mesesPresentes.map((m) => p.meses[m] || 0), p.total]);
      const totalRow = ["TOTAL", ...agg.mesesPresentes.map((m) => agg.monthlyTotal[m] || 0), agg.totalGeral];
      return XLSX.utils.aoa_to_sheet([header, ...data, totalRow]);
    };

    const buildSheetUF = (agg) => {
      const header = ["Estado", ...agg.mesesPresentes.map((m) => MESES[m - 1]), "Total"];
      const data = agg.ufTotals.map((p) => [UF_NAMES[p.uf] || p.uf, ...agg.mesesPresentes.map((m) => p.meses[m] || 0), p.total]);
      return XLSX.utils.aoa_to_sheet([header, ...data]);
    };

    XLSX.utils.book_append_sheet(wb, buildSheet(aggAntes), "Antes - Transportadora");
    XLSX.utils.book_append_sheet(wb, buildSheetUF(aggAntes), "Antes - Estado");
    XLSX.utils.book_append_sheet(wb, buildSheet(aggDepois), "Pos - Transportadora");
    XLSX.utils.book_append_sheet(wb, buildSheetUF(aggDepois), "Pos - Estado");

    const wsComp = XLSX.utils.aoa_to_sheet([
      ["Mês", "Antes da Entrega", "Pós Entrega", "Proporção Pós/Antes"],
      ...comparacaoMensal.map((r) => [r.mes, r.Antes, r.Depois, r.Antes > 0 ? (r.Depois / r.Antes).toFixed(2) : "-"]),
    ]);
    XLSX.utils.book_append_sheet(wb, wsComp, "Comparacao Mensal");

    const wsCompSem = XLSX.utils.aoa_to_sheet([["Semana", "Antes da Entrega", "Pós Entrega"], ...comparacaoSemanal.map((r) => [r.semana, r.Antes, r.Depois])]);
    XLSX.utils.book_append_sheet(wb, wsCompSem, "Comparacao Semanal");

    XLSX.writeFile(wb, "reversas_antes_pos_entrega.xlsx");
  };

  return (
    <div style={{ fontFamily: "'Inter', -apple-system, BlinkMacSystemFont, sans-serif", background: C.cinzaFundo, minHeight: "100%", padding: 24, color: C.texto }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", flexWrap: "wrap", gap: 12, marginBottom: 18 }}>
        <div>
          <h1 style={{ fontSize: 22, fontWeight: 800, margin: 0 }}>Reversas Parça — Antes x Pós Entrega</h1>
          <div style={{ color: C.cinzaTexto, fontSize: 13.5, marginTop: 4 }}>
            Acompanhamento de volume de cancelamento/devolução — antes da entrega (terceiros) e pós entrega (logística reversa)
          </div>
        </div>
        <button onClick={exportExcel} style={{ background: C.cinzaCard, border: `1px solid ${C.cinzaBorda}`, color: C.texto, padding: "9px 16px", borderRadius: 8, fontSize: 13.5, fontWeight: 600, cursor: "pointer", height: "fit-content" }}>
          ⬇️ Exportar Excel (todas as abas)
        </button>
      </div>

      {loadError && (
        <div style={{ background: C.vermelhoLight, color: C.vermelho, padding: "10px 14px", borderRadius: 8, marginBottom: 16, fontSize: 13.5 }}>{loadError}</div>
      )}

      {/* Navegação principal */}
      <div style={{ display: "flex", gap: 10, marginBottom: 20, flexWrap: "wrap" }}>
        {[
          ["antes", "🚚 Antes da Entrega", C.laranja],
          ["depois", "📦 Pós Entrega", C.azul],
          ["comparacao", "📊 Comparação Antes x Pós", C.verde],
        ].map(([key, label, cor]) => (
          <button key={key} onClick={() => setSection(key)} style={{
            padding: "10px 18px", borderRadius: 10, cursor: "pointer", fontSize: 14, fontWeight: 700,
            border: section === key ? `2px solid ${cor}` : `1px solid ${C.cinzaBorda}`,
            background: section === key ? cor + "18" : C.cinzaCard,
            color: section === key ? cor : C.cinzaTexto,
          }}>{label}</button>
        ))}
      </div>

      {section === "antes" && (
        <div>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12, flexWrap: "wrap", gap: 8 }}>
            <div style={{ fontSize: 12.5, color: C.cinzaTexto }}>Base atual: <strong>{fileNameAntes}</strong> · Devolução Terceiras (cancelamento/devolução antes da entrega ao cliente)</div>
            <label style={{ background: C.laranja, color: "#fff", padding: "8px 14px", borderRadius: 8, fontSize: 13, fontWeight: 600, cursor: "pointer" }}>
              📂 Carregar novo CSV
              <input type="file" accept=".csv" style={{ display: "none" }} onChange={(e) => handleFileAntes(e.target.files[0])} />
            </label>
          </div>
          <DatasetView agg={aggAntes} subtab={subtabAntes} setSubtab={setSubtabAntes} corPrincipal={C.laranja} tituloVolume="Antes da Entrega"
            categoryView={{
              tabLabel: "🏷️ Terceira x BulkyLog",
              node: (
                <CategoryComparisonView
                  agg={aggAntesCategoria}
                  catA="TERCEIRA" catB="BULKYLOG"
                  labelA="Transportadora Terceira" labelB="BulkyLog (Malha Própria)"
                  colorA={C.laranja} colorB={C.azul}
                />
              ),
            }}
          />
        </div>
      )}

      {section === "depois" && (
        <div>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12, flexWrap: "wrap", gap: 8 }}>
            <div style={{ fontSize: 12.5, color: C.cinzaTexto }}>Base atual: <strong>{fileNameDepois}</strong> · Logística Reversa (coleta pós entrega ao cliente)</div>
            <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
              <label style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 13, color: C.cinzaTexto, cursor: "pointer" }}>
                <input type="checkbox" checked={somenteParca} onChange={(e) => setSomenteParca(e.target.checked)} />
                Somente Parça
              </label>
              <label style={{ background: C.azul, color: "#fff", padding: "8px 14px", borderRadius: 8, fontSize: 13, fontWeight: 600, cursor: "pointer" }}>
                📂 Carregar novo CSV
                <input type="file" accept=".csv" style={{ display: "none" }} onChange={(e) => handleFileDepois(e.target.files[0])} />
              </label>
            </div>
          </div>
          <DatasetView agg={aggDepois} subtab={subtabDepois} setSubtab={setSubtabDepois} corPrincipal={C.azul} tituloVolume="Pós Entrega"
            categoryView={{
              tabLabel: "🏷️ Parça x Não Parça",
              node: (
                <CategoryComparisonView
                  agg={aggDepoisCategoria}
                  catA="PARCA" catB="NAO_PARCA"
                  labelA="Parça" labelB="Não Parça"
                  colorA={C.verde} colorB={C.cinzaTexto}
                />
              ),
            }}
          />
        </div>
      )}

      {section === "comparacao" && (
        <div style={{ display: "flex", flexDirection: "column", gap: 18 }}>
          <div style={{ display: "flex", gap: 14, flexWrap: "wrap" }}>
            <KpiCard label="Total Antes da Entrega" value={totalAntes.toLocaleString("pt-BR")} accent={C.laranja} />
            <KpiCard label="Total Pós Entrega" value={totalDepois.toLocaleString("pt-BR")} accent={C.azul} />
            <KpiCard label="Proporção Pós / Antes" value={proporcao !== null ? proporcao.toFixed(1) + "x" : "—"} accent={C.verde}
              sub={<span style={{ fontSize: 12.5, color: C.cinzaTexto }}>p/ cada nota antes, {proporcao !== null ? proporcao.toFixed(1) : "—"} pós entrega</span>} />
          </div>

          <div style={{ background: C.cinzaCard, border: `1px solid ${C.cinzaBorda}`, borderRadius: 12, padding: 18 }}>
            <div style={{ fontWeight: 700, fontSize: 14.5, marginBottom: 12 }}>Comparação Mensal — Antes x Pós Entrega</div>
            <ResponsiveContainer width="100%" height={280}>
              <BarChart data={comparacaoMensal}>
                <CartesianGrid strokeDasharray="3 3" stroke={C.cinzaBorda} vertical={false} />
                <XAxis dataKey="mes" tick={{ fontSize: 12.5, fill: C.cinzaTexto }} axisLine={{ stroke: C.cinzaBorda }} tickLine={false} />
                <YAxis tick={{ fontSize: 12.5, fill: C.cinzaTexto }} axisLine={false} tickLine={false} />
                <Tooltip contentStyle={{ borderRadius: 8, border: `1px solid ${C.cinzaBorda}`, fontSize: 13 }} />
                <Legend wrapperStyle={{ fontSize: 12 }} />
                <Bar dataKey="Antes" fill={C.laranja} radius={[4, 4, 0, 0]} name="Antes da Entrega" />
                <Bar dataKey="Depois" fill={C.azul} radius={[4, 4, 0, 0]} name="Pós Entrega" />
              </BarChart>
            </ResponsiveContainer>
          </div>

          <div style={{ background: C.cinzaCard, border: `1px solid ${C.cinzaBorda}`, borderRadius: 12, padding: 18 }}>
            <div style={{ fontWeight: 700, fontSize: 14.5, marginBottom: 4 }}>Comparação Semanal — Antes x Pós Entrega</div>
            <div style={{ fontSize: 12, color: C.cinzaTexto, marginBottom: 12 }}>Semanas em referência ISO — pode haver leve defasagem entre as duas bases por diferença na regra de cálculo de semana de cada origem</div>
            <ResponsiveContainer width="100%" height={240}>
              <LineChart data={comparacaoSemanal}>
                <CartesianGrid strokeDasharray="3 3" stroke={C.cinzaBorda} vertical={false} />
                <XAxis dataKey="semana" tick={{ fontSize: 10.5, fill: C.cinzaTexto }} axisLine={{ stroke: C.cinzaBorda }} tickLine={false} interval={1} />
                <YAxis tick={{ fontSize: 12.5, fill: C.cinzaTexto }} axisLine={false} tickLine={false} />
                <Tooltip contentStyle={{ borderRadius: 8, border: `1px solid ${C.cinzaBorda}`, fontSize: 13 }} />
                <Legend wrapperStyle={{ fontSize: 12 }} />
                <Line type="monotone" dataKey="Antes" stroke={C.laranja} strokeWidth={2.2} dot={{ r: 2 }} name="Antes da Entrega" />
                <Line type="monotone" dataKey="Depois" stroke={C.azul} strokeWidth={2.2} dot={{ r: 2 }} name="Pós Entrega" />
              </LineChart>
            </ResponsiveContainer>
          </div>

          <div style={{ background: C.cinzaCard, border: `1px solid ${C.cinzaBorda}`, borderRadius: 12, padding: 18, overflowX: "auto" }}>
            <div style={{ fontWeight: 700, fontSize: 14.5, marginBottom: 12 }}>Tabela Comparativa Mensal</div>
            <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 13 }}>
              <thead>
                <tr style={{ borderBottom: `2px solid ${C.cinzaBorda}` }}>
                  <th style={{ textAlign: "left", padding: "8px 6px" }}>Mês</th>
                  <th style={{ textAlign: "right", padding: "8px 6px" }}>Antes da Entrega</th>
                  <th style={{ textAlign: "right", padding: "8px 6px" }}>Pós Entrega</th>
                  <th style={{ textAlign: "right", padding: "8px 6px" }}>Proporção Pós/Antes</th>
                </tr>
              </thead>
              <tbody>
                {comparacaoMensal.map((r, i) => (
                  <tr key={r.mes} style={{ borderBottom: `1px solid ${C.cinzaBorda}`, background: i % 2 === 0 ? C.cinzaFundo : "transparent" }}>
                    <td style={{ padding: "7px 6px", fontWeight: 600 }}>{r.mes}</td>
                    <td style={{ textAlign: "right", padding: "7px 6px" }}>{r.Antes.toLocaleString("pt-BR")}</td>
                    <td style={{ textAlign: "right", padding: "7px 6px" }}>{r.Depois.toLocaleString("pt-BR")}</td>
                    <td style={{ textAlign: "right", padding: "7px 6px" }}>{r.Antes > 0 ? (r.Depois / r.Antes).toFixed(1) + "x" : "—"}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      <div style={{ marginTop: 20, fontSize: 11.5, color: C.cinzaTexto, textAlign: "center" }}>
        Antes da entrega: base Devolução Terceiras · Pós entrega: base Logística Reversa · Correios e Dominalog consolidados automaticamente · Estado identificado por UF ou, na ausência, pela cidade
      </div>
    </div>
  );
}
